public class RabinKarp {
    private static final long MOD  = 1_000_000_007L;
    private static final long BASE = 31L;

    static List<Integer> search(String text, String pattern) {
        int n = text.length(), m = pattern.length();
        List<Integer> result = new ArrayList<>();
        if (m > n) return result;

        long patHash = 0, winHash = 0, power = 1;

        // Compute BASE^(m-1) mod MOD
        for (int i = 0; i < m - 1; i++) power = power * BASE % MOD;

        // Compute initial hashes
        for (int i = 0; i < m; i++) {
            patHash = (patHash * BASE + (pattern.charAt(i) - 'a' + 1)) % MOD;
            winHash = (winHash * BASE + (text.charAt(i)   - 'a' + 1)) % MOD;
        }

        for (int i = 0; i <= n - m; i++) {
            if (winHash == patHash && text.substring(i, i + m).equals(pattern))
                result.add(i);

            if (i < n - m) {
                // Roll: remove leftmost, add rightmost
                winHash = (winHash - (text.charAt(i) - 'a' + 1) * power % MOD + MOD) % MOD;
                winHash = (winHash * BASE + (text.charAt(i + m) - 'a' + 1)) % MOD;
            }
        }
        return result;
    }

    public static void main(String[] args) {
        System.out.println(search("abcabcabc", "abc")); // [0, 3, 6]
        System.out.println(search("aaaa", "aa"));       // [0, 1, 2]
    }
}

public class ZAlgorithm {
    static int[] buildZ(String s) {
        int n = s.length();
        int[] z = new int[n];
        int l = 0, r = 0;
        for (int i = 1; i < n; i++) {
            if (i < r) z[i] = Math.min(r - i, z[i - l]);
            while (i + z[i] < n && s.charAt(z[i]) == s.charAt(i + z[i])) z[i]++;
            if (i + z[i] > r) { l = i; r = i + z[i]; }
        }
        return z;
    }

    // Pattern matching: find all occurrences of pattern in text
    static List<Integer> search(String text, String pattern) {
        String combined = pattern + "#" + text;
        int[] z = buildZ(combined);
        int m = pattern.length();
        List<Integer> result = new ArrayList<>();
        for (int i = m + 1; i < combined.length(); i++)
            if (z[i] == m) result.add(i - m - 1);
        return result;
    }

    public static void main(String[] args) {
        System.out.println(search("abcabcabc", "abc")); // [0, 3, 6]
        int[] z = buildZ("aabxaa");
        System.out.println(Arrays.toString(z)); // [0, 1, 0, 0, 2, 1]
    }
}
